mapper.select:
SELECT *
FROM sprout_tag t1
WHERE
  t1.tag_id = #{tagId}
  AND t1.user_id = #{userId}

mapper.insert:
INSERT INTO sprout_tag (
    tag_name
  , tag_detail
  , tag_color
  , tag_sort_order
  , update_at
  , update_user
  , user_id
) VALUES (
    #{tagName}
  , #{tagDetail}
  , #{tagColor}
  , #{tagSortOrder}
  , #{updateAt}
  , #{updateUser}
  , #{userId}
)

mapper.update:
UPDATE sprout_tag
SET
    tag_name = #{tagName}
  , tag_detail = #{tagDetail}
  , tag_color = #{tagColor}
  , tag_sort_order = #{tagSortOrder}
  , update_at = #{updateAt}
  , update_user = #{updateUser}
WHERE
  tag_id = #{tagId}
  AND user_id = #{userId}

mapper.delete:
DELETE FROM sprout_tag
WHERE tag_id = #{tagId}
AND user_id = #{userId}

mapper.update:
UPDATE
  sprout_tag
SET
  tag_sort_order = #{tagSortOrder}
WHERE
  tag_id = #{tagId}
  AND user_id = #{userId}

mapper.insert:
INSERT INTO sprout_item_tag (
    item_id
  , tag_id
) VALUES (
    #{itemId}
  , #{tagId}
)

mapper.delete:
DELETE FROM
  sprout_item_tag it
USING
  sprout_item i
WHERE
  it.item_id = i.id
    AND it.item_id = #{itemId}
    AND it.tag_id = #{tagId}
    AND i.user_id = #{userId}

mapper.update:
UPDATE sprout_tag
SET
    exp = #{exp}
  , lv  = #{lv}
WHERE
  tag_id  = #{tagId}
  AND user_id = #{userId}
